changeSet.sql:
IF NOT EXISTS (
    SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS
    WHERE TABLE_NAME = 'mode_de_calcul_interet' AND COLUMN_NAME = 'ACTIF'
)
    ALTER TABLE mode_de_calcul_interet ADD ACTIF BIT NOT NULL DEFAULT 1;

IF NOT EXISTS (
    SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS
    WHERE TABLE_NAME = 'FAMILLEPRODUITCREDIT' AND COLUMN_NAME = 'ACTIF'
)
    ALTER TABLE FAMILLEPRODUITCREDIT ADD ACTIF BIT NOT NULL DEFAULT 1;

IF NOT EXISTS (SELECT 1 FROM FAMILLEPRODUITCREDIT WHERE CODEFAMILLEPRODUITCREDIT = N'FAM_ISL')
    INSERT INTO FAMILLEPRODUITCREDIT (CODEFAMILLEPRODUITCREDIT, nomfamilleProduitCredit, VERSION)
    VALUES (N'FAM_ISL', N'Produits Islamiques (Mourabaha / Moucharaka / Ijara)', 0);
